import React from 'react';
import { Card, CardTitle, Metric, StatusBadge } from './Shared';
import { STATUS_META } from '../data/constants';

const WORKFLOW_STEPS = [
  { role: 'Official',     action: 'Complete Persal claim form',   note: 'With all supporting documents',     done: true },
  { role: 'Official',     action: 'Submit to supervisor',          note: 'For approval and signature',         done: true },
  { role: 'Supervisor',   action: 'Approve claim',                 note: 'Verify dates, km, purpose, log sheet', active: true },
  { role: 'HRS Payroll',  action: 'Quality check & Persal capture',note: 'Compile mandate and upload to ECM',  done: false },
  { role: 'DMC Payroll',  action: 'Pay on supplementary',          note: 'Verify payment confirmed on Persal', done: false },
];

export default function Dashboard({ claims, onNav }) {
  const counts = { pending: 0, approved: 0, captured: 0, paid: 0 };
  claims.forEach(c => {
    if (c.status === 'pending') counts.pending++;
    if (c.status === 'approved') counts.approved++;
    if (c.status === 'captured' || c.status === 'ecm' || c.status === 'routed') counts.captured++;
    if (c.status === 'paid') counts.paid++;
  });
  const myTotal = claims.filter(c => c.name.startsWith('DLAMINI')).reduce((s, c) => s + c.amount, 0);

  return (
    <div>
      <div style={{ marginBottom: '1.5rem' }}>
        <div style={{ fontSize: 20, fontWeight: 500 }}>Dashboard</div>
        <div style={{ fontSize: 13, color: 'var(--text2)', marginTop: 4 }}>
          Gauteng Provincial Government — Persal Travel & Subsistence
        </div>
      </div>

      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(4,1fr)', gap: 12, marginBottom: '1.5rem' }}>
        <Metric label="Pending approval"  value={counts.pending}  sub="Supervisor queue" />
        <Metric label="In HRS / capture"  value={counts.captured} sub="Persal & ECM" />
        <Metric label="Paid this month"   value={`R ${myTotal.toFixed(2)}`} sub="YTD total" />
        <Metric label="Total claims"      value={claims.length}   sub="All statuses" />
      </div>

      <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '1rem' }}>
        <Card>
          <CardTitle>Recent claims</CardTitle>
          <table>
            <thead>
              <tr><th>Ref</th><th>Official</th><th>Amount</th><th>Status</th></tr>
            </thead>
            <tbody>
              {claims.slice(0, 6).map(c => (
                <tr key={c.ref}>
                  <td style={{ fontFamily: 'var(--mono)', fontSize: 12 }}>{c.ref}</td>
                  <td>{c.name}</td>
                  <td style={{ fontFamily: 'var(--mono)' }}>R {c.amount.toFixed(2)}</td>
                  <td><StatusBadge status={c.status} /></td>
                </tr>
              ))}
            </tbody>
          </table>
        </Card>

        <Card>
          <CardTitle>Workflow — as-is process</CardTitle>
          <div>
            {WORKFLOW_STEPS.map((step, i) => (
              <div key={i} style={{
                display: 'flex', gap: 12,
                padding: '10px 0',
                borderBottom: i < WORKFLOW_STEPS.length - 1 ? '0.5px solid var(--border)' : 'none',
              }}>
                <div style={{
                  width: 30, height: 30, borderRadius: '50%',
                  display: 'flex', alignItems: 'center', justifyContent: 'center',
                  fontSize: 13, fontWeight: 500, flexShrink: 0,
                  background: step.done ? 'var(--green-bg)' : step.active ? 'var(--blue-bg)' : 'var(--surface2)',
                  color: step.done ? 'var(--green-text)' : step.active ? 'var(--blue-text)' : 'var(--text3)',
                  border: step.active ? '2px solid var(--blue)' : 'none',
                }}>
                  {step.done ? <i className="ti ti-check" style={{ fontSize: 14 }} /> : i + 1}
                </div>
                <div style={{ flex: 1 }}>
                  <div style={{ fontSize: 11, color: 'var(--text3)', marginBottom: 2 }}>{step.role}</div>
                  <div style={{ fontSize: 13, fontWeight: 500 }}>{step.action}</div>
                  <div style={{ fontSize: 12, color: 'var(--text2)', marginTop: 1 }}>{step.note}</div>
                </div>
              </div>
            ))}
          </div>
        </Card>
      </div>
    </div>
  );
}
